// Scheduled run — full result counts
const searches = [
  { search_term: "Site Reliability Engineer", location: "San Jose, CA", distance: 50, results_wanted: 20 },
  { search_term: "SRE", location: "San Francisco, CA", distance: 50, results_wanted: 20 },
  { search_term: "Staff SRE", location: "United States", distance: null, results_wanted: 15 },
  { search_term: "Principal SRE", location: "United States", distance: null, results_wanted: 15 },
  { search_term: "DevOps Engineer", location: "San Jose, CA", distance: 50, results_wanted: 20 },
  { search_term: "Platform Engineer", location: "San Jose, CA", distance: 50, results_wanted: 20 },
  { search_term: "Infrastructure Engineer", location: "San Jose, CA", distance: 50, results_wanted: 15 }
];
const sites = ["indeed", "linkedin", "zip_recruiter", "glassdoor"];
const output = [];
for (const s of searches) {
  for (const site of sites) {
    const payload = { search_term: s.search_term, location: s.location, job_type: "fulltime", is_remote: true, results_wanted: s.results_wanted, site_name: [site], country_indeed: "USA" };
    if (s.distance !== null) payload.distance = s.distance;
    output.push({ json: { body: JSON.stringify(payload), isTest: false } });
  }
}
return output;

// Normalisation — maps JobSpy API response fields to common schema
const crypto = require('crypto');

function makeJobId(source, company, title, url) {
  const raw = `${source}:${(company || "").toLowerCase()}:${(title || "").toLowerCase()}:${(url || "").slice(-40)}`;
  return crypto.createHash('md5').update(raw).digest('hex');
}

function parseSalary(salaryStr) {
  if (!salaryStr) return { min: null, max: null };
  const str = salaryStr.replace(/,/g, '').toLowerCase();
  const hourly = str.includes('/hr') || str.includes('per hour') || str.includes('hourly');
  const nums = str.match(/\d+\.?\d*/g);
  if (!nums) return { min: null, max: null };
  let vals = nums.map(Number);
  if (hourly) vals = vals.map(v => v * 2080);
  if (vals.some(v => v < 1000)) vals = vals.map(v => v * 1000);
  return { min: vals[0] || null, max: vals[1] || vals[0] || null };
}

const output = [];
for (const item of items) {
  const raw = item.json;
  const jobs = Array.isArray(raw.jobs) ? raw.jobs : [raw];
  for (const job of jobs) {
    const source = (job.site || job.source || "unknown").toLowerCase();
    const salary = parseSalary(job.salary || job.salary_range || job.min_amount_str);
    const salMin = job.min_amount ? Math.round(job.min_amount) : salary.min;
    const salMax = job.max_amount ? Math.round(job.max_amount) : salary.max;
    output.push({
      json: {
        job_id: makeJobId(source, job.company, job.title, job.job_url || job.url),
        source: source,
        title: job.title || null,
        company: job.company || null,
        location: job.location || null,
        url: job.job_url || job.url || null,
        salary_min: salMin,
        salary_max: salMax,
        employment_type: job.job_type || job.employment_type || "unknown",
        description: job.description || null,
        posted_at: job.date_posted || job.posted_at || null,
        raw_json: job
      }
    });
  }
}
return output;

const isTest = items[0]?.json?.isTest === true;
if (isTest) {
  return items.map(item => ({ json: { ...item.json, is_new: true } }));
}
return items;

// Job scoring logic
const FILTERS = {
  minSalary: 170000,
  targetSalary: 200000,
  contractKeywords: ["contract", "c2c", "corp-to-corp", "1099", "w2 only", "w2 contract", "6-month", "12-month", "temp"],
  agencyKeywords: ["staffing", "recruiting", "talent", "solutions llc", "consulting group", "resources inc", "workforce"],
  fteKeywords: ["full-time", "full time", "permanent", "fte", "direct hire"],
  juniorKeywords: ["junior", "entry level", "associate", "intern", "graduate"],
  contractIncludeThreshold: 60,
  fteIncludeThreshold: 40,
};

function containsAny(text, keywords) {
  if (!text) return false;
  const lower = text.toLowerCase();
  return keywords.some(k => lower.includes(k));
}

function scoreJob(job) {
  let score = 50;
  let flaggedContract = false;
  const titleAndDesc = `${job.title || ""} ${job.description || ""}`;
  const companyName = job.company || "";
  const salMin = job.salary_min || 0;
  const salMax = job.salary_max || 0;
  const salRef = salMax || salMin;

  if (salRef > 0 && salRef < FILTERS.minSalary) return { score: 0, flaggedContract: false, include: false };
  if (salRef >= FILTERS.targetSalary) score += 10;
  else if (salRef >= FILTERS.minSalary) score += 5;

  const isFTE = job.employment_type === "fulltime" || containsAny(titleAndDesc, FILTERS.fteKeywords);
  if (isFTE) score += 20;

  const isContractTitle = containsAny(titleAndDesc, FILTERS.contractKeywords);
  const isAgency = containsAny(companyName, FILTERS.agencyKeywords);
  if (isContractTitle || isAgency) {
    score -= (isContractTitle ? 30 : 0) + (isAgency ? 20 : 0);
    flaggedContract = true;
  }

  if (containsAny(job.title, FILTERS.juniorKeywords)) score -= 20;
  if (containsAny(titleAndDesc, ["equity", "rsu", "stock options", "espp"])) score += 10;

  const threshold = flaggedContract ? FILTERS.contractIncludeThreshold : FILTERS.fteIncludeThreshold;
  return { score, flaggedContract, include: score >= threshold };
}

const output = [];
for (const item of items) {
  const job = item.json;
  const result = scoreJob(job);
  if (result.include) {
    output.push({ json: { ...job, score: result.score, flagged_contract: result.flaggedContract } });
  }
}
return output;

// Discord formatter — sorted descending by score, includes Ollama summary
const WEBHOOK_BATCH_SIZE = 10;

function formatSalary(min, max) {
  if (!min && !max) return 'Salary not listed';
  const fmt = (n) => `$${Math.round(n / 1000)}k`;
  if (min && max && min !== max) return `${fmt(min)}\u2013${fmt(max)}`;
  return fmt(min || max);
}

function jobEmbed(job) {
  const isContract = job.flagged_contract;
  const emoji = isContract ? '\uD83D\uDFE1' : '\uD83D\uDFE2';
  const tag = isContract ? '[CONTRACT \u26A0\uFE0F]' : '[FTE]';
  const fields = [
    { name: '\uD83D\uDCCD Location', value: job.location || 'Not listed', inline: true },
    { name: '\uD83D\uDCB0 Salary', value: formatSalary(job.salary_min, job.salary_max), inline: true },
    { name: '\uD83D\uDD17 Source', value: (job.source || 'unknown').toUpperCase(), inline: true },
    { name: '\u2B50 Score', value: String(job.score), inline: true },
  ];

  if (job.ollama_summary) {
    fields.push({ name: '\uD83E\uDD16 Summary', value: job.ollama_summary.slice(0, 1024), inline: false });
  }

  return {
    title: `${emoji} ${tag} ${job.title} \u2014 ${job.company || 'Unknown Company'}`,
    url: job.url || '',
    color: isContract ? 0xFFA500 : 0x00C853,
    fields,
    footer: { text: isContract ? 'Flagged: contract/C2C \u2014 included on merit' : 'FTE' }
  };
}

const allJobs = (items[0].json.data || items.map(i => i.json))
  .sort((a, b) => b.score - a.score);

const fteCount = allJobs.filter(j => !j.flagged_contract).length;
const contractCount = allJobs.filter(j => j.flagged_contract).length;

const output = [{
  json: {
    content: `\uD83D\uDCCB **Daily Job Digest** \u2014 ${allJobs.length} new jobs (${fteCount} FTE, ${contractCount} contract)`,
    embeds: []
  }
}];

for (let i = 0; i < allJobs.length; i += WEBHOOK_BATCH_SIZE) {
  output.push({
    json: {
      content: '',
      embeds: allJobs.slice(i, i + WEBHOOK_BATCH_SIZE).map(jobEmbed)
    }
  });
}
return output;

// Ollama summariser — runs after Score Jobs, before Aggregate
// - LinkedIn jobs: skip (no description available via API)
// - Jobs with no description: skip
// - All others: call Ollama llama3.2 for company blurb + 5 bullet takeaways
// - If Ollama errors/times out: graceful fallback message

const OLLAMA_URL = 'http://192.168.1.151:11434/api/generate';
const MODEL = 'llama3.2';
const TIMEOUT_MS = 60000;

async function callOllama(prompt) {
  const body = JSON.stringify({
    model: MODEL,
    prompt: prompt,
    stream: false,
    options: { temperature: 0.3, num_predict: 300 }
  });

  const response = await $http.request({
    method: 'POST',
    url: OLLAMA_URL,
    body: body,
    headers: { 'Content-Type': 'application/json' },
    timeout: TIMEOUT_MS,
  });

  return response.response || response.body?.response || null;
}

const output = [];

for (const item of items) {
  const job = { ...item.json };

  // LinkedIn never provides descriptions via API
  if (job.source === 'linkedin') {
    job.ollama_summary = 'LinkedIn does not provide job descriptions via API so none provided.';
    output.push({ json: job });
    continue;
  }

  // No description available
  if (!job.description) {
    job.ollama_summary = null;
    output.push({ json: job });
    continue;
  }

  const prompt = `You are summarising a job listing for a senior SRE/DevOps engineer reviewing job opportunities.

Job title: ${job.title}
Company: ${job.company || 'Unknown'}
Location: ${job.location || 'Unknown'}

Job description:
${job.description.slice(0, 3000)}

Respond in exactly this format, nothing else:

Company: <2 sentences max about the company>
Takeaways:
• <key takeaway 1>
• <key takeaway 2>
• <key takeaway 3>
• <key takeaway 4>
• <key takeaway 5>`;

  try {
    const result = await callOllama(prompt);
    job.ollama_summary = result ? result.trim() : '(Ollama returned empty response)';
  } catch (err) {
    job.ollama_summary = `(Ollama did not respond: ${err.message || 'timeout'})`;
  }

  output.push({ json: job });
}

return output;

// Test run — 1 random search term, 2 results per site, random offset
