  { search_term: "Principal SRE", location: "United States", distance: null },
  { search_term: "DevOps Engineer", location: "San Jose, CA", distance: 50 },
  { search_term: "Platform Engineer", location: "San Jose, CA", distance: 50 },
  { search_term: "Infrastructure Engineer", location: "San Jose, CA", distance: 50 }
];
const sites = ["indeed", "linkedin", "zip_recruiter", "glassdoor"];
const s = searches[Math.floor(Math.random() * searches.length)];
return sites.map(site => {
  const payload = { search_term: s.search_term, location: s.location, job_type: "fulltime", is_remote: true, results_wanted: 2, offset: Math.floor(Math.random() * 10), site_name: [site], country_indeed: "USA" };
  if (s.distance !== null) payload.distance = s.distance;
  return { json: { body: JSON.stringify(payload), isTest: true } };
});
